class AuthServiceImpl(AuthServiceServicer):
    def Login(self, request, context):
        username = request.username
        password = request.password
        
        password_hash = hashlib.sha256(password.encode()).hexdigest()
        
        if username in users_db and users_db[username] == password_hash:
            token = jwt.encode(
                {
                    'username': username,
                    'exp': datetime.utcnow() + timedelta(hours=24)
                },
                SECRET_KEY,
                algorithm='HS256'
            )
            return LoginResponse(True, token, 'Login successful')
        else:
            return LoginResponse(False, '', 'Invalid credentials')
    
    def ValidateToken(self, request, context):
        token = request.token
        
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
            username = payload.get('username')
            return ValidateTokenResponse(True, username, 'Token is valid')
        except jwt.ExpiredSignatureError:
            return ValidateTokenResponse(False, '', 'Token has expired')
        except jwt.InvalidTokenError:
            return ValidateTokenResponse(False, '', 'Invalid token')

class DataServiceImpl(DataServiceServicer):
    def _validate_token(self, token):
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
            return True, payload.get('username')
        except:
            return False, None
    
    def GetData(self, request, context):
        valid, username = self._validate_token(request.token)
        
        if not valid:
            return GetDataResponse(False, '', 'Invalid or expired token')
        
        data_id = request.data_id
        
        if data_id in data_db:
            data_item = data_db[data_id]
            data_str = f"{data_item['id']}:{data_item['name']}:{data_item['value']}"
            return GetDataResponse(True, data_str, 'Data retrieved successfully')
        else:
            return GetDataResponse(False, '', 'Data not found')
    
    def ListData(self, request, context):
        valid, username = self._validate_token(request.token)
        
        if not valid:
            return ListDataResponse(False, [], 'Invalid or expired token')
        
        limit = min(request.limit, len(data_db))
        items = []
        
        for i, (key, value) in enumerate(data_db.items()):
            if i >= limit:
                break
            items.append(DataItem(value['id'], value['name'], value['value']))
        
        return ListDataResponse(True, items, f'Retrieved {len(items)} items')

