class MicroserviceClient:
    def __init__(self, host='localhost', port=50051):
        self.channel = grpc.insecure_channel(f'{host}:{port}')
        self.auth_stub = AuthServiceStub(self.channel)
        self.data_stub = DataServiceStub(self.channel)
        self.token = None
    
    def login(self, username, password):
        request = LoginRequest(username, password)
        response = self.auth_stub.Login(request)
        
        if response.success:
            self.token = response.token
            print(f'Login successful! Token: {self.token[:20]}...')
        else:
            print(f'Login failed: {response.message}')
        
        return response.success
    
    def validate_token(self, token=None):
        if token is None:
            token = self.token
        
        if not token:
            print('No token available')
            return False
        
        request = ValidateTokenRequest(token)
        response = self.auth_stub.ValidateToken(request)
        
        print(f'Token validation: {response.valid} - {response.message}')
        if response.valid:
            print(f'Username: {response.username}')
        
        return response.valid
    
    def get_data(self, data_id):
        if not self.token:
            print('Not authenticated. Please login first.')
            return None
        
        request = GetDataRequest(self.token, data_id)
        response = self.data_stub.GetData(request)
        
        if response.success:
            print(f'Data retrieved: {response.data}')
        else:
            print(f'Failed to retrieve data: {response.message}')
        
        return response
    
    def list_data(self, limit=10):
        if not self.token:
            print('Not authenticated. Please login first.')
            return None
        
        request = ListDataRequest(self.token, limit)
        response = self.data_stub.ListData(request)
        
        if response.success:
            print(f'Retrieved {len(response.items)} items:')
            for item in response.items:
                print(f'  - ID: {item.id}, Name: {item.name}, Value: {item.value}')
        else:
            print(f'Failed to list data: {response.message}')
        
        return response
    
    def close(self):
        self.channel.close()

